document.addEventListener('DOMContentLoaded', () => {
    const canvas = new fabric.Canvas('editor-canvas', {
        width: 1000,
        height: 1000,
        backgroundColor: '#111', // Solid dark background for contrast
        preserveObjectStacking: true
    });

    function resizeCanvas() {
        const wrapper = document.querySelector('.canvas-wrapper');
        const containerWidth = wrapper.offsetWidth || 400;
        const scale = containerWidth / 1000;
        canvas.setZoom(scale);
        canvas.setWidth(containerWidth);
        canvas.setHeight(containerWidth);
    }

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();

    let bgImage = null;
    let templateImage = null;
    let categoryText = null;
    let mainText = null;

    function refreshLayerOrder() {
        // Strict order: Background (0) -> Template (1) -> Mask (2) -> Category (3) -> Title (4)
        if (bgImage) bgImage.sendToBack();
        if (templateImage) {
            templateImage.bringToFront();
            // Ensure template is above bg
            if (bgImage && canvas.getObjects().indexOf(templateImage) < canvas.getObjects().indexOf(bgImage)) {
                templateImage.bringToFront();
            }
        }
        if (categoryText) categoryText.bringToFront();
        if (mainText) mainText.bringToFront();
        canvas.renderAll();
    }

    // Initialize UI immediately so text is visible even if image fails
    initUI();

    // Load Template from embedded Base64 to bypass CORS/Tainted Canvas issues on local files
    const base64Template = "data:image/png;base64,";
    fabric.Image.fromURL(base64Template, (img) => {
        setupTemplate(img);
    }, { crossOrigin: 'anonymous' });

    function setupTemplate(img) {
        templateImage = img;
        img.set({
            selectable: false,
            evented: false,
            originX: 'left',
            originY: 'top'
        });
        img.scaleToWidth(1000);
        canvas.add(img);
        refreshLayerOrder();
    }

    function initUI() {
        // 1. Category Text
        categoryText = new fabric.IText('NOTICIAS', {
            left: 500,
            top: 963,
            fontFamily: 'Outfit',
            fontWeight: 900,
            fontSize: 40,
            fill: '#FACC15',
            textAlign: 'center',
            originX: 'center',
            originY: 'center',
            selectable: true
        });

        // 3. News Title
        mainText = new fabric.Textbox('TÍTULO DE LA NOTICIA', {
            left: 500,
            top: 350,
            width: 940,
            fontFamily: 'Inter',
            fontWeight: 900,
            fontSize: 60,
            fill: '#ffffff',
            textAlign: 'center',
            originX: 'center',
            originY: 'top',
            selectable: true,
            breakWords: true,
            shadow: new fabric.Shadow({ color: 'rgba(0,0,0,0.8)', blur: 10 })
        });

        canvas.add(categoryText);
        canvas.add(mainText);

        // Sync with Textarea
        const textarea = document.getElementById('news-text');
        textarea.value = mainText.text;
        textarea.addEventListener('input', (e) => {
            mainText.set({ text: e.target.value.toUpperCase() });
            canvas.renderAll();
        });

        // Font size
        document.getElementById('font-size').addEventListener('input', (e) => {
            mainText.set({ fontSize: parseInt(e.target.value) });
            canvas.renderAll();
        });

        // Font family
        document.getElementById('font-family').addEventListener('change', (e) => {
            mainText.set({ fontFamily: e.target.value });
            canvas.renderAll();
        });

        refreshLayerOrder();
    }

    // BG Upload
    document.getElementById('bg-upload').addEventListener('change', (e) => {
        const file = e.target.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (f) => {
            fabric.Image.fromURL(f.target.result, (img) => {
                if (bgImage) canvas.remove(bgImage);
                bgImage = img;
                const scale = Math.max(1000 / img.width, 1000 / img.height);
                img.set({
                    scaleX: scale,
                    scaleY: scale,
                    originX: 'center',
                    originY: 'center',
                    left: 500,
                    top: 500,
                    selectable: true
                });
                canvas.add(img);
                refreshLayerOrder();
            });
        };
        reader.readAsDataURL(file);
    });

    // Cat Buttons
    document.querySelectorAll('.cat-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            document.querySelectorAll('.cat-btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            const cat = btn.getAttribute('data-cat');
            document.getElementById('current-cat-display').textContent = cat;
            if (categoryText) {
                categoryText.set({ text: cat });
                canvas.renderAll();
            }
        });
    });

    // Align Buttons
    document.getElementById('align-left').addEventListener('click', () => { mainText.set({ textAlign: 'left' }); canvas.renderAll(); });
    document.getElementById('align-center').addEventListener('click', () => { mainText.set({ textAlign: 'center' }); canvas.renderAll(); });
    document.getElementById('align-right').addEventListener('click', () => { mainText.set({ textAlign: 'right' }); canvas.renderAll(); });
    document.getElementById('align-justify').addEventListener('click', () => { mainText.set({ textAlign: 'justify' }); canvas.renderAll(); });

    // Reset
    document.getElementById('reset-canvas').addEventListener('click', () => {
        if (confirm('¿Reiniciar editor?')) window.location.reload();
    });

    // Grid
    document.getElementById('toggle-grid').addEventListener('click', () => {
        document.getElementById('grid-overlay').classList.toggle('visible');
    });

    // Download
    document.getElementById('download-btn').addEventListener('click', () => {
        canvas.discardActiveObject();
        refreshLayerOrder();
        const dataURL = canvas.toDataURL({ format: 'png', multiplier: 2 });
        const link = document.createElement('a');
        link.download = `AnacoNews_${Date.now()}.png`;
        link.href = dataURL;
        link.click();
    });

    canvas.on('object:moving', refreshLayerOrder);
    canvas.on('object:scaling', refreshLayerOrder);
});
